    const _safeSet = (id, prop, val) => { const el = document.getElementById(id); if(el) { el[prop] = val; } else { console.warn('[中控台-DEBUG] Element not found:', id); } };
    const _safeGet = (id) => document.getElementById(id);
    console.log("\u{1F680} [疯狂石头] 启动监控中控台");

    function initMonitor() {
        console.log('[中控台-DEBUG] initMonitor() called, document.body:', !!document.body);
        function getRole() {
            if (window.RoleService && window.RoleService.getInstance().role) {
                return window.RoleService.getInstance().role;
            }
            let foundRole = null;
            function traverse(node) {
                if (!foundRole && node && node.youxibi !== undefined && node.dianquan !== undefined && node.level !== undefined && node.name) {
                    foundRole = node;
                    return;
                }
                if (node && node._children) {
                    for (let i = 0; i < node._children.length; i++) traverse(node._children[i]);
                }
            }
            if (window.Laya && window.Laya.stage) traverse(window.Laya.stage);
            return foundRole;
        }

        if (!window._csHookedNetwork) {
            window._csHookedNetwork = true;
            if (window.pomelo && window.pomelo.on) {
                const originalOn = window.pomelo.on;
                window.pomelo.on = function(route, cb) {
                    const wrappedCb = function(data) {
                        try {
                            if (route === 'onGameEnd' || route === 'onPlayerLeaveRoom' || route === 'onPlayerJoinRoom') {
                                setTimeout(() => {
                                    if (window._csFetchNetworkData) window._csFetchNetworkData();
                                }, 1500);
                            }
                        } catch(e) {}
                        return cb.apply(this, arguments);
                    };
                    return originalOn.call(this, route, wrappedCb);
                };
            }
        }

        const requestAsync = (route, msg = null, timeout = 3000) => {
            return new Promise((resolve) => {
                if (!window.pomelo || !window.pomelo.request) return resolve({ code: 500, msg: "网络未就绪" });
                let isResolved = false;
                let timer = setTimeout(() => {
                    if (!isResolved) { isResolved = true; resolve({ code: 408, msg: "请求超时" }); }
                }, timeout);
                window.pomelo.request(route, msg, (res) => {
                    if (!isResolved) { isResolved = true; clearTimeout(timer); resolve(res); }
                });
            });
        };

        const UI_ID = 'crazy-stone-helper-ui-final';
        if (document.getElementById(UI_ID)) document.getElementById(UI_ID).remove();

        const style = document.createElement('style');
        style.innerHTML = `
            #${UI_ID} {
                position: fixed; top: 15px; right: 15px; width: 320px;
                background: rgba(18, 18, 18, 0.95); border: 1px solid #5c4033;
                border-radius: 6px; z-index: 9999999; font-family: 'SimSun', '宋体', sans-serif;
                color: #d2c0a8; box-shadow: 0 5px 20px rgba(0,0,0,0.9);
                user-select: none; backdrop-filter: blur(4px);
            }
            #cs-header {
                background: linear-gradient(180deg, #3a2318 0%, #1e110b 100%);
                padding: 10px 14px; cursor: move; border-bottom: 1px solid #5c4033;
                border-radius: 6px 6px 0 0; display: flex; justify-content: space-between;
                align-items: center; font-weight: bold; color: #fdf5e6; font-size: 15px;
            }
            #cs-refresh-btn {
                background: #5c4033; border: 1px solid #8b5a2b; color: #4cfa09;
                padding: 4px 10px; border-radius: 4px; cursor: pointer; font-size: 13px;
                outline: none; transition: background 0.2s; font-weight: bold;
            }
            #cs-refresh-btn:hover { background: #8b5a2b; color: #fff; }
            #cs-refresh-btn:active { background: #3a2318; transform: scale(0.95); }
            .cs-content { padding: 12px 14px; font-size: 14px; line-height: 1.8; }
            .cs-row { display: flex; justify-content: space-between; border-bottom: 1px dashed #3a2318; padding: 8px 0; align-items: center;}
            .cs-row:last-child { border-bottom: none; }
            .cs-label { color: #888; font-size: 14px;}
            .cs-value { color: #4cfa09; text-align: right; font-weight: bold; font-size: 16px;}
            .cs-value.highlight { color: #0cf6ff; }
            .cs-task-container { display: flex; flex-direction: column; width: 100%; font-size: 13px;}
            .cs-task-item { color: #68a1e7; margin-top: 4px; padding-left: 8px; border-left: 2px solid #5c4033;}
        `;
        document.head.appendChild(style);

        const ui = document.createElement('div');
        ui.id = UI_ID;
        ui.innerHTML = `
            <div id="cs-header">
                <span>⚔️ 监控中控台</span>
                <button id="cs-refresh-btn">刷新</button>
            </div>
            <div class="cs-content">
                <div class="cs-row"><span class="cs-label">角色ID</span><span class="cs-value" id="cs-v-uid">-</span></div>
                <div class="cs-row"><span class="cs-label">双倍剩余</span><span class="cs-value" id="cs-v-double">-</span></div>
                <div class="cs-row"><span class="cs-label">交易次数</span><span class="cs-value" id="cs-v-trade">-</span></div>
                <div class="cs-row"><span class="cs-label">招魂铃</span><span class="cs-value highlight" id="cs-v-bell">-</span></div>
                
                <div class="cs-row" style="border-bottom:none; margin-top:8px; padding-bottom:0;">
                    <span class="cs-label" style="color:#d2c0a8; font-weight:bold; font-size: 14px;">📜 家族任务</span>
                </div>
                <div class="cs-task-container" id="cs-v-family-task"><div class="cs-task-item" style="color:#777">获取中...</div></div>
                
                <div class="cs-row" style="border-bottom:none; margin-top:8px; padding-bottom:0;">
                    <span class="cs-label" style="color:#d2c0a8; font-weight:bold; font-size: 14px;">📜 日常任务</span>
                </div>
                <div class="cs-task-container" id="cs-v-daily-task"><div class="cs-task-item" style="color:#777">获取中...</div></div>
            </div>
        `;
        document.body.appendChild(ui);

        ui.addEventListener('keydown', function(e) {
            if (e.key === ' ' || e.key === 'Enter') { e.preventDefault(); e.stopPropagation(); }
        });

        const header = document.getElementById('cs-header');
        let isDragging = false, startX, startY, initialX, initialY;
        header.addEventListener('mousedown', (e) => {
            if (e.target.id === 'cs-refresh-btn') return;
            isDragging = true; startX = e.clientX; startY = e.clientY;
            const rect = ui.getBoundingClientRect();
            initialX = rect.left; initialY = rect.top;
            ui.style.right = 'auto'; ui.style.left = initialX + 'px'; ui.style.top = initialY + 'px';
        });
        document.addEventListener('mousemove', (e) => {
            if (!isDragging) return;
            ui.style.left = (initialX + e.clientX - startX) + 'px';
            ui.style.top = (initialY + e.clientY - startY) + 'px';
        });
        document.addEventListener('mouseup', () => { isDragging = false; });

        const fetchTasksWithDetails = async (listRoute, category) => {
            let listRes = await requestAsync(listRoute);
            if (listRes.code !== 200 || !listRes.data) return `<div class="cs-task-item" style="color:#777">获取失败/无家族</div>`;
            if (listRes.data.length === 0) return `<div class="cs-task-item" style="color:#777">暂无进行中的任务</div>`;
            
            let html = "";
            for (let t of listRes.data) {
                if (t.status === 2) {
                    html += `<div class="cs-task-item">${t.name} <span style="color:#4cfa09; float:right; font-weight:bold;">[ 已完成 ]</span></div>`;
                } else {
                    let detailRes = await requestAsync("area.playerHandler.getTaskDetail", { id: t.id, category: category });
                    if (detailRes.code === 200 && detailRes.data) {
                        let d = detailRes.data;
                        let current = d.count !== undefined ? d.count : (d.targetGoodsLeaveCount !== undefined ? d.targetGoodsLeaveCount : 0);
                        let target = d.targetCount !== undefined ? d.targetCount : (t.targetCount !== undefined ? t.targetCount : '?');
                        html += `<div class="cs-task-item">${t.name} <span style="color:#f8c020; float:right; font-weight:bold;">[ ${current}/${target} ]</span></div>`;
                    } else {
                        html += `<div class="cs-task-item">${t.name} <span style="color:#f8c020; float:right; font-weight:bold;">[ 进行中 ]</span></div>`;
                    }
                }
            }
            return html;
        };

        window._csFetchNetworkData = async () => {
            console.log('[中控台-DEBUG] _csFetchNetworkData called, UI exists:', !!document.getElementById('crazy-stone-helper-ui-final'));
            if (!document.getElementById('crazy-stone-helper-ui-final')) { console.warn('[中控台-DEBUG] UI已不存在，跳过数据刷新'); return; }
            const btn = document.getElementById('cs-refresh-btn');
            if(btn) { btn.innerText = "读取中..."; btn.style.color = "#fff"; }
            try {
                const role = getRole();
                if (!role) {
                    _safeSet('cs-v-uid', 'innerText', '未获取到');
                    (() => { const el = _safeGet('cs-v-uid'); if(el) el.style.color = '#888'; })()
                    return;
                }
                _safeSet('cs-v-uid', 'innerText', role.id || "未知")
                (() => { const el = _safeGet('cs-v-uid'); if(el) el.style.color = '#4cfa09'; })()
                
                let fc = role.gameConfig ? role.gameConfig.freeDoubleExpCount : null;
                if (fc !== null && fc !== undefined && typeof fc === 'number') {
                    _safeSet('cs-v-double', 'innerText', fc + ' 次')
                } else {
                    let tipOk = false;
                    if (role && role._children) {
                        for (let i = 0; i < role._children.length; i++) {
                            let child = role._children[i];
                            if ((child && child._skinUrl && String(child._skinUrl).indexOf('double-exp') > -1) ||
                                (child && child._skinPath && String(child._skinPath).indexOf('double-exp') > -1)) {
                                tipOk = true; break;
                            }
                        }
                    }
                    _safeSet('cs-v-double', 'innerText', tipOk ? '有额度' : '--');
                }

                let bagArr = role.bag;
                if (!bagArr || !Array.isArray(bagArr)) {
                    let bagRes = await requestAsync("area.playerHandler.getPlayerBag");
                    if (bagRes.code === 200 && bagRes.data && bagRes.data.content) {
                        bagArr = bagRes.data.content;
                        if (role.setBag) role.setBag(bagArr); 
                    }
                }
                let bellCount = 0;
                if (bagArr) {
                    let bell = bagArr.find(item => item.type === 3500 || item.goodsId === 3500);
                    if (bell) bellCount = bell.count;
                }
                _safeSet('cs-v-bell', 'innerText', bellCount + ' 个')

                const tradeRes = await requestAsync("area.playerHandler.getTradeList");
                if (tradeRes.code === 200) {
                    _safeSet('cs-v-trade', 'innerText', (tradeRes.count !== undefined ? tradeRes.count : "无限制") + ' 次')
                }

