                background: #1e1e1e; border: 1px solid #5c4033; border-top: none; border-radius: 0 0 4px 4px;
                z-index: 10; display: none; box-shadow: 0 4px 10px rgba(0,0,0,0.8);
            }
            .cs-skin-dropdown-item {
                padding: 6px 10px; font-size: 12px; color: #d2c0a8; cursor: pointer; border-bottom: 1px solid #2a2a2a;
            }
            .cs-skin-dropdown-item:hover { background: #3a2318; color: #fff; }
            .cs-skin-dropdown::-webkit-scrollbar { width: 6px; }
            .cs-skin-dropdown::-webkit-scrollbar-thumb { background: #5c4033; border-radius: 3px; }
            .cs-skin-btns { display: flex; justify-content: space-between; margin-top: 15px; gap: 15px; }
            .cs-skin-btn {
                flex: 1; padding: 8px 0; border: none; border-radius: 4px; font-size: 14px;
                font-weight: bold; cursor: pointer; outline: none; transition: 0.2s; color: #fff;
            }
            #btn-replace { background: linear-gradient(180deg, #8b5a2b, #5c4033); border: 1px solid #a05203; }
            #btn-replace:hover { background: linear-gradient(180deg, #a05203, #8b5a2b); }
            #btn-replace:active { transform: scale(0.96); }
            #btn-restore { background: linear-gradient(180deg, #555, #333); border: 1px solid #666; }
            #btn-restore:hover { background: linear-gradient(180deg, #666, #444); }
            #btn-restore:active { transform: scale(0.96); }
        `;
        document.head.appendChild(style);

        const ui = document.createElement('div');
        ui.id = UI_ID;
        ui.innerHTML = `
            <div id="cs-skin-header">
                <span>🎽 皮肤幻化修改器</span>
                <span id="cs-skin-close">×</span>
            </div>
            <div class="cs-skin-content">
                <div class="cs-skin-row" title="10开头限圣女, 11限女侠, 12限黑火, 13限剑客, 14及以上通用">
                    <span class="cs-skin-label">头 部</span>
                    <input type="text" id="cs-head" class="cs-skin-input" placeholder="输入关键字或ID" autocomplete="off">
                    <div class="cs-skin-dropdown" id="dd-cs-head"></div>
                </div>
                <div class="cs-skin-row" title="20开头限圣女, 21限女侠, 22限黑火, 23限剑客, 24及以上通用">
                    <span class="cs-skin-label">衣 服</span>
                    <input type="text" id="cs-body" class="cs-skin-input" placeholder="输入关键字或ID" autocomplete="off">
                    <div class="cs-skin-dropdown" id="dd-cs-body"></div>
                </div>
                <div class="cs-skin-row">
                    <span class="cs-skin-label">背部(单)</span>
                    <input type="text" id="cs-wing-s" class="cs-skin-input" placeholder="与双翅互斥" autocomplete="off">
                    <div class="cs-skin-dropdown" id="dd-cs-wing-s"></div>
                </div>
                <div class="cs-skin-row">
                    <span class="cs-skin-label">背部(双)</span>
                    <input type="text" id="cs-wing-d" class="cs-skin-input" placeholder="与单翅互斥" autocomplete="off">
                    <div class="cs-skin-dropdown" id="dd-cs-wing-d"></div>
                </div>
                <div class="cs-skin-row" title="游戏底层逻辑：特殊皇冠会直接覆盖头部">
                    <span class="cs-skin-label">配 件</span>
                    <input type="text" id="cs-peijian" class="cs-skin-input" placeholder="冠军之冠等" autocomplete="off">
                    <div class="cs-skin-dropdown" id="dd-cs-peijian"></div>
                </div>
                
                <div class="cs-skin-btns">
                    <button id="btn-replace" class="cs-skin-btn">执行替换 🚀</button>
                    <button id="btn-restore" class="cs-skin-btn">恢复原貌 ↺</button>
                </div>
            </div>
        `;
        document.body.appendChild(ui);

        const header = document.getElementById('cs-skin-header');
        let isDragging = false, startX, startY, initialX, initialY;
        
        header.addEventListener('mousedown', (e) => {
            if (e.target.id === 'cs-skin-close') return;
            isDragging = true; startX = e.clientX; startY = e.clientY;
            const rect = ui.getBoundingClientRect();
            initialX = rect.left; initialY = rect.top;
            ui.style.right = 'auto'; ui.style.left = initialX + 'px'; ui.style.top = initialY + 'px';
        });
        document.addEventListener('mousemove', (e) => {
            if (!isDragging) return;
            ui.style.left = (initialX + e.clientX - startX) + 'px';
            ui.style.top = (initialY + e.clientY - startY) + 'px';
        });
        document.addEventListener('mouseup', () => { isDragging = false; });
        document.getElementById('cs-skin-close').onclick = () => ui.remove();

        ui.addEventListener('keydown', function(e) {
            if (e.key === ' ' || e.key === 'Enter') e.stopPropagation();
        });

        function setupAutocomplete(inputId) {
            const input = document.getElementById(inputId);
            const dropdown = document.getElementById('dd-' + inputId);
            const data = EQUIP_DICT[inputId];

            function renderList(filterTxt) {
                dropdown.innerHTML = '';
                let count = 0;
                data.forEach(item => {
                    if (item.includes(filterTxt)) {
                        let div = document.createElement('div');
                        div.className = 'cs-skin-dropdown-item';
                        div.innerText = item;
                        div.onmousedown = (e) => { 
                            e.preventDefault(); 
                            input.value = item;
                            dropdown.style.display = 'none';
                            triggerExclusivity(inputId);
                        };
                        dropdown.appendChild(div);
                        count++;
                    }
                });
                dropdown.style.display = count > 0 ? 'block' : 'none';
            }

            input.onfocus = () => renderList(input.value);
            input.oninput = () => {
                renderList(input.value);
                triggerExclusivity(inputId);
            };
            input.onblur = () => { dropdown.style.display = 'none'; };
        }

        function triggerExclusivity(inputId) {
            const wingS = document.getElementById('cs-wing-s');
            const wingD = document.getElementById('cs-wing-d');
            if (inputId === 'cs-wing-s' && wingS.value !== '') wingD.value = '';
            if (inputId === 'cs-wing-d' && wingD.value !== '') wingS.value = '';
        }

        Object.keys(EQUIP_DICT).forEach(id => setupAutocomplete(id));

        function getGameRole() {
            try { return window.Laya.stage._children[0]._children[0].role; } catch (e) { return null; }
        }

        function getIdFromInput(inputId) {
            const val = document.getElementById(inputId).value;
            if (!val) return null;
            const match = val.match(/ID:(\d+)/);
            return match ? parseInt(match[1]) : null;
        }

        document.getElementById('btn-replace').onclick = function() {
            const role = getGameRole();
            if (!role) return alert("❌ 未检测到角色，请确认已进入游戏房间或战斗！");

            const headId = getIdFromInput('cs-head');
            const bodyId = getIdFromInput('cs-body');
            const wingSId = getIdFromInput('cs-wing-s');
            const wingDId = getIdFromInput('cs-wing-d');
            const peijianId = getIdFromInput('cs-peijian');

            if (!headId && !bodyId && !wingSId && !wingDId && !peijianId) {
                return alert("⚠️ 请至少填写一个要替换的装备！");
            }

            try {
                if (!window._originalSkinsData) {
                    window._originalSkinsData = {
                        head: role.head ? Object.assign({}, role.head) : null,
                        body: role.body ? Object.assign({}, role.body) : null,
                        wing: role.wing ? Object.assign({}, role.wing) : null,
                        peijian: role.peijian ? Object.assign({}, role.peijian) : null
                    };
                }

                if ((headId || peijianId) && role.headEquip) { role.removeChild(role.headEquip); role.headEquip = null; }
                if (bodyId && role.bodyEquip) { role.removeChild(role.bodyEquip); role.bodyEquip = null; }
                if ((wingSId || wingDId)) {
                    if(role.wingEquip) { role.removeChild(role.wingEquip); role.wingEquip = null; }
                    if(role.wingEquip2) { role.removeChild(role.wingEquip2); role.wingEquip2 = null; }
                }

                if (peijianId) role.peijian = { type: peijianId, goodsType: peijianId };
                if (headId) role.head = { type: headId, goodsType: headId };
                if (bodyId) role.body = { type: bodyId, goodsType: bodyId };
                
                if (wingSId) {
                    role.wing = { type: wingSId, goodsType: wingSId };
                } else if (wingDId) {
                    role.wing = { type: wingDId, goodsType: wingDId, double: true };
                }

                if (headId || peijianId) role.initHead(); 
                if (bodyId) role.initBody();
                if (wingSId || wingDId) role.initWing();

                this.innerText = "替换成功 ✔";
                this.blur();
                setTimeout(() => { this.innerText = "执行替换 🚀"; }, 1500);

            } catch (e) {
                console.error(e);
                alert("❌ 替换过程发生异常，请检查控制台报错。");
            }
        };

        document.getElementById('btn-restore').onclick = function() {
            if (!window._originalSkinsData) {
                return alert("⚠️ 您还没进行过替换，暂无备份数据可以恢复！");
            }

            const role = getGameRole();
            if (!role) return alert("❌ 未检测到角色，请确认已进入游戏！");

            try {
                if (role.headEquip) { role.removeChild(role.headEquip); role.headEquip = null; }
                if (role.bodyEquip) { role.removeChild(role.bodyEquip); role.bodyEquip = null; }
                if (role.wingEquip) { role.removeChild(role.wingEquip); role.wingEquip = null; }
                if (role.wingEquip2) { role.removeChild(role.wingEquip2); role.wingEquip2 = null; }

                role.peijian = window._originalSkinsData.peijian;
                role.head = window._originalSkinsData.head;
                role.initHead(); 

                role.body = window._originalSkinsData.body;
                if (role.body) role.initBody();

                role.wing = window._originalSkinsData.wing;
                if (role.wing) role.initWing();

                document.getElementById('cs-head').value = '';
                document.getElementById('cs-body').value = '';
                document.getElementById('cs-wing-s').value = '';
                document.getElementById('cs-wing-d').value = '';
                document.getElementById('cs-peijian').value = '';

                this.innerText = "恢复成功 ✔";
                this.blur();
                setTimeout(() => { this.innerText = "恢复原貌 ↺"; }, 1500);

            } catch (e) {
                console.error(e);
            }
        };
    }

    // 依次启动两个独立组件

    initSkinModifier();
